content.content:
  1→.chapter-reader {
  2→    width: 100%;
  3→    max-width: 700px;
  4→    box-sizing: border-box;
  5→    margin: 0 auto;
  6→    padding: 0 16px 40px;
  7→}
  8→
  9→.chapter-reader-loading {
 10→    display: flex;
 11→    justify-content: center;
 12→    padding: 60px 0;
 13→}
 14→
 15→.chapter-reader-error {
 16→    text-align: center;
 17→    color: var(--text-secondary);
 18→    padding: 40px 0;
 19→}
 20→
 21→/* Progress bar */
 22→.chapter-progress-track {
 23→    position: fixed;
 24→    top: 0;
 25→    left: 0;
 26→    right: 0;
 27→    height: 3px;
 28→    background: var(--border-light);
 29→    z-index: 100;
 30→}
 31→
 32→.chapter-progress-fill {
 33→    height: 100%;
 34→    width: 0;
 35→    background: var(--accent-purple);
 36→    transition: width 0.1s linear;
 37→}
 38→
 39→/* Header */
 40→.chapter-reader-header {
 41→    display: flex;
 42→    align-items: flex-start;
 43→    gap: 12px;
 44→    padding: 20px 0 16px;
 45→    border-bottom: 1px solid var(--border-light);
 46→    margin-bottom: 24px;
 47→}
 48→
 49→.chapter-reader-back {
 50→    width: 36px;
 51→    height: 36px;
 52→    border: none;
 53→    background: var(--bg-secondary);
 54→    border-radius: 8px;
 55→    display: flex;
 56→    align-items: center;
 57→    justify-content: center;
 58→    cursor: pointer;
 59→    transition: background-color 0.12s ease;
 60→    flex-shrink: 0;
 61→    margin-top: 2px;
 62→}
 63→
 64→.chapter-reader-back:hover {
 65→    background: var(--bg-hover);
 66→}
 67→
 68→.chapter-reader-header-info {
 69→    min-width: 0;
 70→}
 71→
 72→.chapter-reader-chapter-label {
 73→    font-size: 0.75rem;
 74→    color: var(--text-muted);
 75→    text-transform: uppercase;
 76→    letter-spacing: 0.5px;
 77→    font-weight: 500;
 78→}
 79→
 80→.chapter-reader-title {
 81→    font-size: 1.3rem;
 82→    font-weight: 700;
 83→    color: var(--text-primary);
 84→    margin: 4px 0 0 0;
 85→    line-height: 1.25;
 86→}
 87→
 88→/* Content */
 89→.chapter-reader-body {
 90→    min-height: 300px;
 91→    position: relative;
 92→}
 93→
 94→.chapter-reader-content {
 95→    font-size: 1.05rem;
 96→    line-height: 1.85;
 97→    color: var(--text-primary);
 98→    outline: none;
 99→}
100→
101→.chapter-reader-content .editor-paragraph {
102→    margin-bottom: 1em;
103→}
104→
105→/* Navigation */
106→.chapter-reader-nav {
107→    display: flex;
108→    justify-content: space-between;
109→    align-items: stretch;
110→    gap: 12px;
111→    margin-top: 40px;
112→    padding-top: 20px;
113→    border-top: 1px solid var(--border-light);
114→}
115→
116→.chapter-nav-btn {
117→    display: flex;
118→    align-items: center;
119→    gap: 6px;
120→    padding: 12px 16px;
121→    border: 1px solid var(--border-light);
122→    border-radius: 10px;
123→    background: none;
124→    color: var(--text-secondary);
125→    font-size: 0.82rem;
126→    cursor: pointer;
127→    transition: background-color 0.12s ease;
128→    max-width: 48%;
129→}
130→
131→.chapter-nav-btn:hover {
132→    background: var(--bg-hover);
133→}
134→
135→.chapter-nav-btn span {
136→    white-space: nowrap;
137→    overflow: hidden;
138→    text-overflow: ellipsis;
139→}
140→
141→.chapter-nav-prev {
142→    text-align: left;
143→}
144→
145→.chapter-nav-next {
146→    text-align: right;
147→    margin-left: auto;
148→}
149→
150→@media (max-width: 480px) {
151→    .chapter-reader {
152→        padding: 0 12px 32px;
153→        padding-bottom: 5rem;
154→    }
155→
156→    .chapter-reader-title {
157→        font-size: 1.1rem;
158→    }
159→
160→    .chapter-reader-content {
161→        font-size: 0.98rem;
162→        line-height: 1.75;
163→    }
164→
165→    .chapter-nav-btn {
166→        padding: 10px 12px;
167→        font-size: 0.78rem;
168→    }
169→}
170→
