172→/* ═══════════════════════════════════════════════
173→   Paragraph Comment Layer (pcl-)
174→   ═══════════════════════════════════════════════ */
175→
176→/* Warm paragraph hover — signals commentability */
177→.chapter-reader-content .editor-paragraph[data-paragraph-index] {
178→    transition: background-color 0.25s ease;
179→    border-radius: 3px;
180→}
181→
182→.chapter-reader-content .editor-paragraph[data-paragraph-index]:hover {
183→    background-color: var(--bg-selection);
184→}
185→
186→.pcl-layer {
187→    position: absolute;
188→    top: 0;
189→    left: 0;
190→    right: 0;
191→    bottom: 0;
192→    pointer-events: none;
193→    z-index: 1;
194→}
195→
196→.pcl-badge-anchor {
197→    position: absolute;
198→    right: -4px;
199→    pointer-events: none;
200→    display: flex;
201→    align-items: flex-start;
202→    padding-top: 3px;
203→    padding-left: 20px;
204→    opacity: 0;
205→    transition: opacity 0.15s ease;
206→}
207→
208→.pcl-badge-anchor.pcl-badge-visible {
209→    opacity: 1;
210→    pointer-events: auto;
211→}
212→
213→.pcl-badge {
214→    display: inline-flex;
215→    align-items: center;
216→    gap: 4px;
217→    padding: 5px 8px;
218→    border: 1px solid var(--bg-glass-border);
219→    border-radius: 20px;
220→    background: var(--bg-glass);
221→    backdrop-filter: blur(16px);
222→    -webkit-backdrop-filter: blur(16px);
223→    color: var(--text-secondary);
224→    cursor: pointer;
225→    font-family: var(--font-ui);
226→    font-size: 0.68rem;
227→    font-weight: 600;
228→    letter-spacing: 0.02em;
229→    white-space: nowrap;
230→    box-shadow: var(--shadow-card-sm);
231→    transition: color 0.2s ease, border-color 0.2s ease,
232→                background-color 0.2s ease, box-shadow 0.2s ease,
233→                transform 0.2s ease;
234→}
235→
236→.pcl-badge:hover {
237→    color: var(--accent-amber);
238→    border-color: var(--accent-amber);
239→    background: var(--bg-selection-active);
240→    box-shadow: 0 0 0 3px var(--bg-selection), var(--shadow-card-sm);
241→    transform: scale(1.06);
242→}
243→
244→.pcl-badge-active {
245→    color: var(--accent-amber);
246→    border-color: rgba(212, 168, 83, 0.3);
247→    background: var(--bg-selection);
248→    box-shadow: 0 0 12px rgba(212, 168, 83, 0.1);
249→}
250→
251→.pcl-badge-active:hover {
252→    border-color: var(--accent-amber);
253→    background: var(--bg-selection-active);
254→    box-shadow: 0 0 0 3px var(--bg-selection-active),
255→                0 0 16px rgba(212, 168, 83, 0.14);
256→}
257→
258→.pcl-badge svg {
259→    flex-shrink: 0;
260→}
261→
262→.pcl-badge-count {
263→    line-height: 1;
264→    min-width: 8px;
265→    text-align: center;
266→}
267→
268→@media (max-width: 768px) {
269→    .pcl-badge {
270→        padding: 4px 6px;
271→        font-size: 0.64rem;
272→    }
273→
274→    /* No hover state on touch devices */
275→    .chapter-reader-content .editor-paragraph[data-paragraph-index]:hover {
276→        background-color: transparent;
277→    }
278→}
279→
