281→/* ═══════════════════════════════════════════════
282→   Comment Panel (cp-)
283→   ═══════════════════════════════════════════════ */
284→
285→.cp-backdrop {
286→    position: fixed;
287→    inset: 0;
288→    background: var(--bg-overlay);
289→    backdrop-filter: blur(4px);
290→    -webkit-backdrop-filter: blur(4px);
291→    z-index: 200;
292→}
293→
294→.cp-panel {
295→    display: flex;
296→    flex-direction: column;
297→    background: var(--bg-card);
298→    z-index: 201;
299→    overflow: hidden;
300→    box-shadow: var(--shadow-modal);
301→}
302→
303→.cp-panel-desktop {
304→    position: fixed;
305→    top: 0;
306→    right: 0;
307→    width: 380px;
308→    height: 100%;
309→    border-left: 1px solid var(--border-card);
310→}
311→
312→.cp-panel-mobile {
313→    position: fixed;
314→    bottom: 0;
315→    left: 0;
316→    right: 0;
317→    height: 70vh;
318→    border-radius: 16px 16px 0 0;
319→    border-top: 1px solid var(--border-card);
320→}
321→
322→.cp-drag-handle {
323→    width: 36px;
324→    height: 4px;
325→    border-radius: 2px;
326→    background: var(--text-faint);
327→    margin: 10px auto 0;
328→    flex-shrink: 0;
329→}
330→
331→/* ── Header ── */
332→.cp-header {
333→    display: flex;
334→    align-items: center;
335→    justify-content: space-between;
336→    padding: 0.85rem 1.15rem;
337→    border-bottom: 1px solid var(--border-card);
338→    flex-shrink: 0;
339→}
340→
341→.cp-header-left {
342→    display: flex;
343→    align-items: center;
344→    gap: 8px;
345→}
346→
347→.cp-title {
348→    font-family: var(--font-ui);
349→    font-size: 0.88rem;
350→    font-weight: 700;
351→    color: var(--text-heading);
352→    margin: 0;
353→}
354→
355→.cp-count {
356→    font-family: var(--font-ui);
357→    font-size: 0.62rem;
358→    font-weight: 600;
359→    color: var(--accent-amber);
360→    background: var(--bg-selection);
361→    padding: 2px 7px;
362→    border-radius: 10px;
363→    line-height: 1.4;
364→}
365→
366→.cp-close {
367→    display: flex;
368→    align-items: center;
369→    justify-content: center;
370→    width: 28px;
371→    height: 28px;
372→    border: none;
373→    background: none;
374→    color: var(--text-faint);
375→    cursor: pointer;
376→    border-radius: 50%;
377→    transition: background-color 0.15s ease, color 0.15s ease;
378→}
379→
380→.cp-close:hover {
381→    background: var(--bg-pill);
382→    color: var(--text-heading);
383→}
384→
385→/* ── Paragraph preview ── */
386→.cp-preview {
387→    display: flex;
388→    gap: 12px;
389→    padding: 14px 1.15rem;
390→    background: var(--bg-selection);
391→    flex-shrink: 0;
392→    border-bottom: 1px solid var(--border-card);
393→}
394→
395→.cp-preview-bar {
396→    width: 3px;
397→    min-height: 100%;
398→    border-radius: 2px;
399→    background: var(--accent-amber);
400→    flex-shrink: 0;
401→}
402→
403→.cp-preview-text {
404→    font-family: var(--font-serif);
405→    font-size: 0.82rem;
406→    font-style: italic;
407→    line-height: 1.6;
408→    color: var(--text-secondary);
409→    margin: 0;
410→    display: -webkit-box;
411→    -webkit-line-clamp: 3;
412→    -webkit-box-orient: vertical;
413→    overflow: hidden;
414→}
415→
416→/* ── Comment list ── */
417→.cp-list {
418→    flex: 1;
419→    overflow-y: auto;
420→    overflow-x: hidden;
421→    padding: 0.5rem 0;
422→}
423→
424→.cp-list::-webkit-scrollbar {
425→    width: 5px;
426→}
427→
428→.cp-list::-webkit-scrollbar-thumb {
429→    background: var(--accent-amber);
430→    border-radius: 4px;
431→}
432→
433→.cp-list::-webkit-scrollbar-track {
434→    background: var(--bg-pill);
435→}
436→
437→.cp-loading {
438→    display: flex;
439→    justify-content: center;
440→    align-items: center;
441→    padding: 40px 0;
442→}
443→
444→/* ── Empty state ── */
445→.cp-empty {
446→    display: flex;
447→    flex-direction: column;
448→    align-items: center;
449→    padding: 48px 24px;
450→    text-align: center;
451→}
452→
453→.cp-empty-icon {
454→    width: 48px;
455→    height: 48px;
456→    border-radius: 50%;
457→    background: var(--bg-selection);
458→    display: flex;
459→    align-items: center;
460→    justify-content: center;
461→    margin-bottom: 14px;
462→}
463→
464→.cp-empty-icon svg {
465→    color: var(--accent-amber);
466→    opacity: 0.7;
467→}
468→
469→.cp-empty-title {
470→    font-family: var(--font-ui);
471→    font-size: 0.88rem;
472→    font-weight: 600;
473→    color: var(--text-heading);
474→    margin: 0 0 4px;
475→}
476→
477→.cp-empty-hint {
478→    font-family: var(--font-serif);
479→    font-size: 0.8rem;
480→    font-style: italic;
481→    color: var(--text-muted);
482→}
483→
484→/* ── Input area ── */
485→.cp-input-area {
486→    display: flex;
487→    flex-direction: column;
488→    padding: 0.75rem 1.15rem;
489→    border-top: 1px solid var(--border-card);
490→    gap: 0.45rem;
491→    flex-shrink: 0;
492→}
493→
494→.cp-reply-indicator {
495→    display: inline-flex;
496→    align-items: center;
497→    gap: 5px;
498→    padding: 3px 10px;
499→    background: var(--bg-selection);
500→    border-radius: 20px;
501→    font-family: var(--font-ui);
502→    font-size: 0.72rem;
503→    font-weight: 500;
504→    color: var(--accent-amber);
505→    align-self: flex-start;
506→}
507→
508→.cp-reply-indicator button {
509→    display: flex;
510→    align-items: center;
511→    justify-content: center;
512→    border: none;
513→    background: none;
514→    color: var(--text-muted);
515→    cursor: pointer;
516→    padding: 0;
517→    margin-left: 2px;
518→    font-size: 0.88rem;
519→    line-height: 1;
520→    transition: color 0.15s ease;
521→}
522→
523→.cp-reply-indicator button:hover {
524→    color: var(--text-heading);
525→}
526→
527→.cp-input-row {
528→    display: flex;
529→    align-items: flex-end;
530→    gap: 0.75rem;
531→}
532→
533→.cp-textarea {
534→    flex: 1;
535→    font-family: var(--font-ui);
536→    font-size: 0.84rem;
537→    background-color: var(--bg-pill);
538→    color: var(--text-primary);
539→    border: 1px solid var(--border-card);
540→    border-radius: 10px;
541→    padding: 0.55rem 0.75rem;
542→    resize: none;
543→    min-height: 1.4rem;
544→    max-height: 80px;
545→    outline: none;
546→    overflow-y: auto;
547→    transition: border-color 0.2s ease;
548→}
549→
550→.cp-textarea:focus {
551→    border-color: var(--accent-amber);
552→}
553→
554→.cp-textarea::placeholder {
555→    color: var(--text-faint);
556→    font-style: italic;
557→}
558→
559→.cp-submit {
560→    cursor: pointer;
561→    border: none;
562→    padding: 0.4rem 1.1rem;
563→    border-radius: 20px;
564→    background-color: var(--accent-amber);
565→    color: #ffffff;
566→    font-family: var(--font-ui);
567→    font-size: 0.78rem;
568→    font-weight: 600;
569→    flex-shrink: 0;
570→    transition: opacity 0.15s ease;
571→}
572→
573→.cp-submit:hover {
574→    opacity: 0.88;
575→}
576→
577→.cp-submit:disabled {
578→    cursor: default;
579→    opacity: 0.4;
580→}
581→
582→.cp-action-row {
583→    display: flex;
584→    align-items: center;
585→    justify-content: flex-end;
586→}
587→
588→.cp-char-count {
589→    font-family: var(--font-ui);
590→    font-size: 0.68rem;
591→    font-weight: 500;
592→    color: var(--text-faint);
593→    margin: 0;
594→    transition: color 0.15s ease;
595→}
596→
597→.cp-char-warn {
598→    color: var(--accent-amber);
599→    font-weight: 600;
600→}
601→
602→.cp-char-red {
603→    color: var(--color-danger);
604→    font-weight: 650;
605→}
606→
607→
608→/* ═══════════════════════════════════════════════
609→   Chapter Comment Card (ccc-)
610→   ═══════════════════════════════════════════════ */
611→
612→.ccc-card {
613→    position: relative;
614→    display: flex;
615→    align-items: stretch;
616→    padding: 0.75rem 1.15rem;
617→    border-bottom: 1px solid var(--border-card);
618→    transition: background-color 0.15s ease;
619→}
620→
621→.ccc-card:last-child {
622→    border-bottom: none;
623→}
624→
625→.ccc-card:hover {
626→    background-color: var(--bg-pill);
627→}
628→
629→.ccc-reply {
630→    margin-left: 20px;
631→    position: relative;
632→    border-bottom: none;
633→    padding: 0.55rem 1rem;
634→}
635→
636→.ccc-reply:hover {
637→    background-color: transparent;
638→}
639→
640→.ccc-thread-line {
641→    position: absolute;
642→    left: -0.65rem;
643→    top: 0;
644→    bottom: 0;
645→    width: 2px;
646→    background-color: var(--border-card);
647→    border-radius: 1px;
648→    transition: background-color 0.2s ease;
649→}
650→
651→.ccc-card:hover > .ccc-thread-line {
652→    background-color: var(--accent-amber);
653→}
654→
655→.ccc-content {
656→    display: flex;
657→    flex-direction: column;
658→    gap: 0.3rem;
659→    flex: 1;
660→    min-width: 0;
661→}
662→
663→/* ── User row ── */
664→.ccc-user-row {
665→    display: flex;
666→    align-items: center;
667→    gap: 0.35rem;
668→}
669→
670→.ccc-avatar-wrap {
671→    display: inline-flex;
672→    align-items: center;
673→    justify-content: center;
674→    border-radius: 50%;
675→    cursor: pointer;
676→    flex-shrink: 0;
677→}
678→
679→.ccc-ring-legend {
680→    border: 2px solid #FFD700;
681→    box-shadow: 0 0 8px 1px rgba(255, 215, 0, 0.3);
682→}
683→
684→.ccc-ring-og {
685→    border: 2px solid #9B59FF;
686→    box-shadow: 0 0 8px 1px rgba(155, 89, 255, 0.3);
687→}
688→
689→.ccc-avatar {
690→    width: 22px;
691→    height: 22px;
692→    border-radius: 50%;
693→    object-fit: cover;
694→    cursor: pointer;
695→    user-select: none;
696→}
697→
698→.ccc-name {
699→    font-family: var(--font-ui);
700→    font-size: 0.78rem;
701→    font-weight: 600;
702→    color: var(--text-heading);
703→    cursor: pointer;
704→    transition: color 0.15s ease;
705→    white-space: nowrap;
706→    overflow: hidden;
707→    text-overflow: ellipsis;
708→    max-width: 140px;
709→}
710→
711→.ccc-name:hover {
712→    color: var(--accent-amber);
713→    text-decoration: underline;
714→}
715→
716→.ccc-dot {
717→    color: var(--text-separator);
718→    font-size: 0.75rem;
719→    line-height: 1;
720→}
721→
722→.ccc-date {
723→    font-family: var(--font-ui);
724→    font-size: 0.7rem;
725→    color: var(--text-faint);
726→    white-space: nowrap;
727→}
728→
729→/* ── Comment body ── */
730→.ccc-body {
731→    font-family: var(--font-serif);
732→    font-size: 0.85rem;
733→    line-height: 1.65;
734→    color: var(--text-body);
735→    margin: 0;
736→    word-break: break-word;
737→}
738→
739→/* ── Actions ── */
740→.ccc-actions {
741→    display: flex;
742→    align-items: center;
743→    gap: 0.6rem;
744→    padding-top: 0.15rem;
745→}
746→
747→.ccc-action-btn {
748→    display: inline-flex;
749→    align-items: center;
750→    gap: 0.3rem;
751→    cursor: pointer;
752→    background: none;
753→    border: none;
754→    padding: 0.2rem 0.5rem;
755→    border-radius: 6px;
756→    font-family: var(--font-ui);
757→    font-size: 0.72rem;
758→    font-weight: 500;
759→    color: var(--text-muted);
760→    transition: color 0.15s ease, background-color 0.15s ease;
761→}
762→
763→.ccc-action-btn:hover {
764→    color: var(--accent-amber);
765→    background-color: var(--bg-pill);
766→}
767→
768→.ccc-replies {
769→    overflow: hidden;
770→    padding-left: 0.5rem;
771→}
772→
773→/* ── Mobile responsive ── */
774→@media (max-width: 480px) {
775→    .cp-panel-desktop {
776→        width: 100%;
777→    }
778→
779→    .cp-header {
780→        padding: 0.7rem 0.85rem;
781→    }
782→
783→    .cp-preview {
784→        padding: 12px 0.85rem;
