  1→import { useState, useEffect, useRef } from 'react';
  2→import { useAuth } from '../../../Context/useAuth';
  3→import { useQueryClient } from '@tanstack/react-query';
  4→import { useChapterComments } from '../hooks/useStoryData';
  5→import { useAddChapterComment } from '../hooks/useStoryMutations';
  6→import { motion } from 'framer-motion';
  7→import { BeatLoader } from 'react-spinners';
  8→import ChapterCommentCard from './ChapterCommentCard';
  9→
 10→const MAX_CHARS = 300;
 11→
 12→const CommentPanel = ({ chapterId, activeComment, onClose }) => {
 13→    const { user, session } = useAuth();
 14→    const token = session?.access_token;
 15→    const queryClient = useQueryClient();
 16→
 17→    const [body, setBody] = useState('');
 18→    const [replyTo, setReplyTo] = useState(null);
 19→    const [isMobile, setIsMobile] = useState(window.innerWidth <= 768);
 20→    const textareaRef = useRef(null);
 21→    const listRef = useRef(null);
 22→
 23→    const { paragraphIndex, fingerprint, text } = activeComment;
 24→
 25→    const { data: comments, isLoading } = useChapterComments(chapterId, paragraphIndex, token);
 26→    const addComment = useAddChapterComment(token);
 27→
 28→    useEffect(() => {
 29→        const handleResize = () => setIsMobile(window.innerWidth <= 768);
 30→        window.addEventListener('resize', handleResize);
 31→        return () => window.removeEventListener('resize', handleResize);
 32→    }, []);
 33→
 34→    useEffect(() => {
 35→        setReplyTo(null);
 36→        setBody('');
 37→    }, [paragraphIndex]);
 38→
 39→    const handleReply = (comment) => {
 40→        setReplyTo(comment);
 41→        textareaRef.current?.focus();
 42→    };
 43→
 44→    const handleSubmit = () => {
 45→        const trimmed = body.trim();
 46→        if (!trimmed || trimmed.length > MAX_CHARS) return;
 47→
 48→        const userData = user?.userData?.[0];
 49→
 50→        const data = {
 51→            comment: trimmed,
 52→            paragraph_index: paragraphIndex,
 53→            paragraph_fingerprint: fingerprint,
 54→        };
 55→        if (replyTo) {
 56→            data.parent_id = replyTo.id;
 57→        }
 58→
 59→        const optimisticComment = {
 60→            id: `optimistic-${Date.now()}`,
 61→            comment: trimmed,
 62→            paragraph_index: paragraphIndex,
 63→            parent_id: replyTo?.id || null,
 64→            created_at: new Date().toISOString(),
 65→            user_id: userData?.id,
 66→            users: {
 67→                id: userData?.id,
 68→                name: userData?.name,
 69→                image_url: userData?.image_url,
 70→                badge: userData?.badge,
 71→                username: userData?.username,
 72→            },
 73→            replies: [],
 74→        };
 75→
 76→        const prevComments = queryClient.getQueryData(['chapterComments', chapterId, paragraphIndex]);
 77→        const prevCounts = queryClient.getQueryData(['chapterCommentCounts', chapterId]);
 78→
 79→        queryClient.setQueryData(['chapterComments', chapterId, paragraphIndex], (old) => {
 80→            if (!old) return [optimisticComment];
 81→            if (replyTo) {
 82→                return old.map((c) =>
 83→                    c.id === replyTo.id
 84→                        ? { ...c, replies: [...(c.replies || []), optimisticComment] }
 85→                        : c
 86→                );
 87→            }
 88→            return [optimisticComment, ...old];
 89→        });
 90→
 91→        queryClient.setQueryData(['chapterCommentCounts', chapterId], (old) => {
 92→            if (!old) return { [paragraphIndex]: 1 };
 93→            return { ...old, [paragraphIndex]: (old[paragraphIndex] || 0) + 1 };
 94→        });
 95→
 96→        addComment.mutate(
 97→            { chapterId, data },
 98→            {
 99→                onError: () => {
100→                    queryClient.setQueryData(['chapterComments', chapterId, paragraphIndex], prevComments);
101→                    queryClient.setQueryData(['chapterCommentCounts', chapterId], prevCounts);
102→                },
103→            }
104→        );
105→
106→        setBody('');
107→        setReplyTo(null);
108→    };
109→
110→    const handleKeyDown = (e) => {
111→        if (e.key === 'Enter' && !e.shiftKey) {
112→            e.preventDefault();
113→            handleSubmit();
114→        }
115→    };
116→
117→    const commentList = comments || [];
118→    const isLoggedIn = !!token;
119→    const charCount = body.length;
120→
121→    const panelVariants = isMobile
122→        ? { initial: { y: '100%' }, animate: { y: 0 }, exit: { y: '100%' } }
123→        : { initial: { x: '100%' }, animate: { x: 0 }, exit: { x: '100%' } };
124→
125→    return (
126→        <>
127→            <motion.div
128→                className="cp-backdrop"
129→                initial={{ opacity: 0 }}
130→                animate={{ opacity: 1 }}
131→                exit={{ opacity: 0 }}
132→                transition={{ duration: 0.2 }}
133→                onClick={onClose}
134→            />
135→
136→            <motion.div
137→                className={`cp-panel ${isMobile ? 'cp-panel-mobile' : 'cp-panel-desktop'}`}
138→                variants={panelVariants}
139→                initial="initial"
140→                animate="animate"
141→                exit="exit"
142→                transition={{ type: 'spring', damping: 25, stiffness: 200 }}
143→            >
144→                {isMobile && <div className="cp-drag-handle" />}
145→
146→                <div className="cp-header">
147→                    <div className="cp-header-left">
148→                        <h3 className="cp-title">Comments</h3>
149→                        {commentList.length > 0 && (
150→                            <span className="cp-count">{commentList.length}</span>
151→                        )}
152→                    </div>
153→                    <button className="cp-close" onClick={onClose} aria-label="Close comments">
154→                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
155→                            <line x1="18" y1="6" x2="6" y2="18" />
156→                            <line x1="6" y1="6" x2="18" y2="18" />
157→                        </svg>
158→                    </button>
159→                </div>
160→
161→                <div className="cp-preview">
162→                    <div className="cp-preview-bar" />
163→                    <p className="cp-preview-text">{text}</p>
164→                </div>
165→
166→                <div className="cp-list" ref={listRef}>
167→                    {isLoading ? (
168→                        <div className="cp-loading">
169→                            <BeatLoader size={8} color="var(--accent-amber)" />
170→                        </div>
171→                    ) : commentList.length === 0 ? (
172→                        <div className="cp-empty">
173→                            <div className="cp-empty-icon">
174→                                <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
175→                                    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
176→                                </svg>
177→                            </div>
178→                            <p className="cp-empty-title">Start the conversation</p>
179→                            <span className="cp-empty-hint">Share your thoughts on this passage</span>
180→                        </div>
181→                    ) : (
182→                        commentList.map((c) => (
183→                            <ChapterCommentCard
184→                                key={c.id}
185→                                comment={c}
186→                                onReply={handleReply}
187→                            />
188→                        ))
189→                    )}
190→                </div>
191→
192→                {isLoggedIn && (
193→                    <div className="cp-input-area">
194→                        {replyTo && (
195→                            <div className="cp-reply-indicator">
196→                                <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
197→                                    <polyline points="9 17 4 12 9 7" />
198→                                    <path d="M20 18v-2a4 4 0 0 0-4-4H4" />
199→                                </svg>
200→                                <span>{replyTo.users?.name}</span>
201→                                <button onClick={() => setReplyTo(null)} aria-label="Cancel reply">&times;</button>
202→                            </div>
203→                        )}
204→                        <div className="cp-input-row">
205→                            <textarea
206→                                ref={textareaRef}
207→                                className="cp-textarea"
208→                                placeholder="Share a thought..."
209→                                value={body}
210→                                onChange={(e) => setBody(e.target.value.slice(0, MAX_CHARS))}
211→                                onKeyDown={handleKeyDown}
212→                                rows={1}
213→                            />
214→                            <button
215→                                className="cp-submit"
216→                                onClick={handleSubmit}
217→                                disabled={!body.trim() || charCount > MAX_CHARS}
218→                            >
219→                                Post
220→                            </button>
221→                        </div>
222→                        <div className="cp-action-row">
223→                            <span className={`cp-char-count ${charCount >= 280 ? (charCount >= MAX_CHARS ? 'cp-char-red' : 'cp-char-warn') : ''}`}>
224→                                {charCount}/{MAX_CHARS}
225→                            </span>
226→                        </div>
227→                    </div>
228→                )}
229→            </motion.div>
230→        </>
231→    );
232→};
233→
234→export default CommentPanel;
